const express = require("express");
const router = express.Router();
const authMiddleware = require("../middleware/authMiddleware");
const {
  registerOrLogin,
  getProfile,
  updateProfile,
  getUserByWallet,
  verifyWallet,
  listUsers,
  updateUserRole
} = require("../controllers/userController");

router.post("/auth", registerOrLogin);

router.get("/verify/:wallet", verifyWallet);

router.get("/wallet/:wallet", getUserByWallet);

router.get("/profile", authMiddleware, getProfile);

router.put("/profile", authMiddleware, updateProfile);

router.get("/list", authMiddleware, listUsers);

router.put("/:walletAddress/role", authMiddleware, updateUserRole);

module.exports = router;
